import React, { useState, useEffect, useRef } from 'react';
import { useTheme } from '../context/ThemeContext';
import { FaSun, FaMoon, FaBars, FaTimes } from 'react-icons/fa';
import './Navbar.css';

const NAV_ITEMS = ['Home', 'About', 'Skills', 'Projects', 'Certificates', 'Contact'];

const Navbar = () => {
    const { theme, toggleTheme } = useTheme();
    const [scrolled, setScrolled] = useState(false);
    const [activeSection, setActiveSection] = useState('home');
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    const [pillStyle, setPillStyle] = useState({ left: 0, width: 0 });
    const navRef = useRef(null);
    const linkRefs = useRef({});

    // Glass effect on scroll
    useEffect(() => {
        const handleScroll = () => setScrolled(window.scrollY > 50);
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    // IntersectionObserver — auto-highlight section in view
    useEffect(() => {
        const observers = [];
        NAV_ITEMS.forEach(item => {
            const id = item.toLowerCase();
            const el = document.getElementById(id);
            if (!el) return;
            const observer = new IntersectionObserver(
                ([entry]) => { if (entry.isIntersecting) setActiveSection(id); },
                { threshold: 0.2, rootMargin: '-60px 0px -40% 0px' }
            );
            observer.observe(el);
            observers.push(observer);
        });
        return () => observers.forEach(o => o.disconnect());
    }, []);

    // Move the sliding pill
    const updatePill = () => {
        const activeEl = linkRefs.current[activeSection];
        const containerEl = navRef.current;
        if (!activeEl || !containerEl) return;
        const containerRect = containerEl.getBoundingClientRect();
        const activeRect = activeEl.getBoundingClientRect();
        setPillStyle({
            left: activeRect.left - containerRect.left,
            width: activeRect.width,
        });
    };

    useEffect(() => {
        const raf = requestAnimationFrame(updatePill);
        return () => cancelAnimationFrame(raf);
    }, [activeSection]);

    useEffect(() => {
        window.addEventListener('resize', updatePill);
        return () => window.removeEventListener('resize', updatePill);
    }, [activeSection]);

    const handleNavClick = (e, item) => {
        e.preventDefault();
        const id = item.toLowerCase();
        setActiveSection(id);
        const el = document.getElementById(id);
        if (el) el.scrollIntoView({ behavior: 'smooth' });
        setIsMobileMenuOpen(false);
    };

    return (
        <nav className={`navbar ${scrolled ? 'scrolled' : ''}`}>
            <div className="w-full px-6 lg:px-12 nav-content" style={{ height: 'var(--nav-height)' }}>

                {/* Logo */}
                <div
                    className="text-[1.1rem] font-extrabold tracking-wide w-[50px] h-[50px] flex items-center justify-center cursor-pointer rounded-[10px] border-2 border-[var(--primary-color)] shrink-0 transition-shadow duration-400"
                    style={{
                        background: 'linear-gradient(135deg, var(--primary-color), var(--secondary-color))',
                        WebkitBackgroundClip: 'text',
                        WebkitTextFillColor: 'transparent',
                        boxShadow: '0 0 12px rgba(168,85,247,0.35)',
                    }}
                    onMouseEnter={e => e.currentTarget.style.boxShadow = '0 0 22px rgba(168,85,247,0.65)'}
                    onMouseLeave={e => e.currentTarget.style.boxShadow = '0 0 12px rgba(168,85,247,0.35)'}
                    onClick={() => {
                        setActiveSection('home');
                        document.getElementById('home')?.scrollIntoView({ behavior: 'smooth' });
                    }}
                >
                    AK
                </div>

                {/* Nav pill container */}
                <div ref={navRef} className="desktop-menu">
                    {/* Sliding background pill */}
                    <div
                        className="desktop-menu-pill"
                        style={{
                            left: pillStyle.left,
                            width: pillStyle.width,
                        }}
                    />

                    {NAV_ITEMS.map(item => {
                        const id = item.toLowerCase();
                        const isActive = activeSection === id;
                        return (
                            <a
                                key={item}
                                href={`#${id}`}
                                ref={el => { if (el) linkRefs.current[id] = el; }}
                                onClick={e => handleNavClick(e, item)}
                                className={`desktop-menu-link ${isActive ? 'active' : ''}`}
                            >
                                {item}
                            </a>
                        );
                    })}
                </div>

                <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                    {/* Theme toggle */}
                    <button
                        onClick={toggleTheme}
                        className="theme-toggle"
                        aria-label="Toggle theme"
                    >
                        {theme === 'dark' ? <FaSun /> : <FaMoon />}
                    </button>

                    {/* Mobile Menu Toggle */}
                    <button
                        onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                        className={`mobile-menu-toggle ${isMobileMenuOpen ? 'open' : ''}`}
                        aria-label="Toggle menu"
                    >
                        <div className="hamburger-lines">
                            <span className="line line1"></span>
                            <span className="line line2"></span>
                            <span className="line line3"></span>
                        </div>
                    </button>
                </div>
            </div>

            {/* Mobile Menu Dropdown */}
            <div className={`mobile-menu ${isMobileMenuOpen ? 'open' : ''}`}>
                <div className="mobile-menu-inner">
                    {NAV_ITEMS.map(item => {
                        const id = item.toLowerCase();
                        const isActive = activeSection === id;
                        return (
                            <a
                                key={`mobile-${item}`}
                                href={`#${id}`}
                                onClick={e => handleNavClick(e, item)}
                                className={`mobile-menu-link ${isActive ? 'active' : ''}`}
                            >
                                {item}
                            </a>
                        );
                    })}
                </div>
            </div>
        </nav>
    );
};

export default Navbar;

import { motion } from 'framer-motion';
import React from 'react';


// Explicitly not using Tailwind, sticking to inline styles or CSS modules would be fine,
// but for "Senior" feel, reusable styled components or clean BEM CSS is good.
// I will use standard CSS classes defined in index.css for simplicity as per "Vanilla CSS" preference in prompt, 
// wrapped in framer-motion components.

const ButtonCallback = ({ children, onClick, variant = 'primary', type = 'button' }) => {
    return (
        <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            className={`btn btn-${variant}`}
            onClick={onClick}
            type={type}
        >
            {children}
        </motion.button>
    );
};

export default ButtonCallback;

import React, { useEffect, useRef, useState } from 'react';
import './CustomCursor.css';

const CustomCursor = () => {
    const cursorRef = useRef(null);
    const cursorDotRef = useRef(null);
    const [isHovering, setIsHovering] = useState(false);
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        const cursor = cursorRef.current;
        const cursorDot = cursorDotRef.current;

        const moveCursor = (e) => {
            // Show cursor when moving (in case it started hidden)
            if (!isVisible) setIsVisible(true);

            const { clientX: x, clientY: y } = e;

            // Main cursor (outer circle) - using slightly smoother animation via requestAnimationFrame logic implicitly handled by browser optimization or CSS 
            // strict tracking for dot
            if (cursorDot) {
                cursorDot.style.left = `${x}px`;
                cursorDot.style.top = `${y}px`;
            }

            // Follower cursor (outer circle) - using simple direct update, CSS handles smoothness
            if (cursor) {
                cursor.style.left = `${x}px`;
                cursor.style.top = `${y}px`;
            }
        };

        const handleMouseDown = () => setIsHovering(true);
        const handleMouseUp = () => setIsHovering(false);

        // Check for hoverable elements
        const handleLinkHoverEvents = () => {
            const handleMouseEnter = () => setIsHovering(true);
            const handleMouseLeave = () => setIsHovering(false);

            const hoverables = document.querySelectorAll('a, button, .btn, input, textarea, .hover-trigger');

            hoverables.forEach(el => {
                el.addEventListener('mouseenter', handleMouseEnter);
                el.addEventListener('mouseleave', handleMouseLeave);
            });

            return () => {
                hoverables.forEach(el => {
                    el.removeEventListener('mouseenter', handleMouseEnter);
                    el.removeEventListener('mouseleave', handleMouseLeave);
                });
            };
        };

        // Initial setup
        document.addEventListener('mousemove', moveCursor);
        document.addEventListener('mousedown', handleMouseDown);
        document.addEventListener('mouseup', handleMouseUp);

        // Dynamic update for single page app navigation if needed, 
        // but a MutationObserver is better for robust SPA tracking. 
        // For simplicity, we track widespread common elements.
        const cleanupLinks = handleLinkHoverEvents();

        // MutationObserver to attach listeners to new elements (like after route changes or modal opens)
        const observer = new MutationObserver(() => {
            // Re-attach listeners is expensive, simpler to delegate or just re-run for this demo
            // For better perf in production, we'd use event delegation or a single global listener checking e.target
        });

        // Event delegation for hovering (more performant than attaching to all elements)
        const handleMouseOver = (e) => {
            if (e.target.tagName === 'A' ||
                e.target.tagName === 'BUTTON' ||
                e.target.closest('.btn') ||
                e.target.closest('a') ||
                e.target.closest('button') ||
                e.target.tagName === 'INPUT' ||
                e.target.tagName === 'TEXTAREA') {
                setIsHovering(true);
            } else {
                setIsHovering(false);
            }
        };

        document.addEventListener('mouseover', handleMouseOver);

        return () => {
            document.removeEventListener('mousemove', moveCursor);
            document.removeEventListener('mousedown', handleMouseDown);
            document.removeEventListener('mouseup', handleMouseUp);
            document.removeEventListener('mouseover', handleMouseOver);
            cleanupLinks();
        };
    }, [isVisible]);

    // Hide on mobile/touch devices
    if (typeof navigator !== 'undefined' && /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent)) {
        return null;
    }

    return (
        <>
            <div
                ref={cursorRef}
                className={`custom-cursor-outline ${isHovering ? 'hover' : ''}`}
            />
            <div
                ref={cursorDotRef}
                className={`custom-cursor-dot ${isHovering ? 'hover' : ''}`}
            />
        </>
    );
};

export default CustomCursor;

import React, { useRef } from 'react';
import { motion, useInView } from 'framer-motion';

const About = () => {
    const ref = useRef(null);
    const isInView = useInView(ref, { once: true, margin: "-100px" });

    return (
        <section id="about" className="section" ref={ref} style={{ position: 'relative', overflow: 'hidden' }}>
            {/* LARGE BACKGROUND TEXT to fill space */}
            <div style={{
                position: 'absolute',
                top: '50%',
                left: '50%',
                transform: 'translate(-50%, -50%)',
                fontSize: '25vw',
                fontWeight: '900',
                color: 'rgba(255,255,255,0.02)',
                zIndex: 0,
                whiteSpace: 'nowrap',
                pointerEvents: 'none',
                fontFamily: 'var(--font-heading)',
                textTransform: 'uppercase'
            }}>
                ABOUT
            </div>

            <div className="container" style={{ position: 'relative', zIndex: 1, maxWidth: '1000px' }}>
                <motion.h2
                    className="section-title"
                    initial={{ opacity: 0, y: 20 }}
                    animate={isInView ? { opacity: 1, y: 0 } : {}}
                    transition={{ duration: 0.6 }}
                    style={{
                        fontSize: 'clamp(3rem, 8vw, 4.5rem)',
                        textAlign: 'center',
                        marginBottom: '4rem',
                        fontFamily: 'var(--font-heading)',
                        fontWeight: '900',
                        letterSpacing: '-0.04em'
                    }}
                >
                    About <span style={{ color: 'var(--primary-color)' }}>Me</span>
                </motion.h2>

                <motion.div
                    initial={{ opacity: 0, y: 30 }}
                    animate={isInView ? { opacity: 1, y: 0 } : {}}
                    transition={{ duration: 0.8, delay: 0.2 }}
                    style={{
                        fontSize: '1.5rem',
                        color: 'var(--text-secondary)',
                        lineHeight: 1.7,
                        textAlign: 'center',
                        fontFamily: 'var(--font-body)',
                        fontWeight: '400'
                    }}
                >
                    <p style={{ marginBottom: '30px' }}>
                        I am <span style={{ color: 'var(--text-main)', fontWeight: '700' }}>Aman</span>, a first-year undergraduate fueled by a curiosity for <span style={{ color: 'var(--secondary-color)', fontWeight: '600' }}>building digital experiences</span>.
                        My journey into software development is driven by a desire to turn ideas into functional, <span style={{ color: 'var(--primary-color)', fontWeight: '600' }}>pixel-perfect reality</span>.
                    </p>
                    <p style={{ marginBottom: '30px' }}>
                        I'm currently immersing myself in the modern web ecosystem—mastering <span style={{ color: 'var(--text-main)', fontWeight: '600' }}>React</span>, JavaScript, and CSS to craft intuitive user interfaces.
                        Beyond the code, I believe in learning by doing, constantly pushing the boundaries of my knowledge.
                    </p>
                    <p>
                        I am looking to connect with like-minded developers, collaborate on innovative solutions, and build a robust foundation for a <span style={{ color: 'var(--secondary-color)', fontWeight: '600' }}>future in software engineering</span>.
                    </p>
                </motion.div>

                {/* Info Tiles to fill bottom space */}
                <div style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                    gap: '20px',
                    marginTop: '60px'
                }}>
                    {[
                        { label: 'Location', value: 'India', icon: 'fa-location-dot' },
                        { label: 'Education', value: '1st Year BE', icon: 'fa-graduation-cap' },
                        { label: 'Interests', value: 'Web & Crypto', icon: 'fa-laptop-code' }
                    ].map((item, idx) => (
                        <motion.div
                            key={idx}
                            initial={{ opacity: 0, y: 20 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.4 + (idx * 0.1) }}
                            style={{
                                background: 'rgba(255,255,255,0.03)',
                                padding: '30px',
                                borderRadius: '24px',
                                border: '1px solid rgba(255,255,255,0.05)',
                                textAlign: 'center'
                            }}
                        >
                            <i className={`fa-solid ${item.icon}`} style={{ fontSize: '1.5rem', color: 'var(--primary-color)', marginBottom: '15px', display: 'block' }}></i>
                            <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', textTransform: 'uppercase', marginBottom: '5px', letterSpacing: '1px' }}>{item.label}</div>
                            <div style={{ fontSize: '1.2rem', fontWeight: '700', color: 'var(--text-main)' }}>{item.value}</div>
                        </motion.div>
                    ))}
                </div>
            </div>
        </section>
    );
};

export default About;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import doppelgangerCert from '../../assets/openpools_doppelganger.png';

const certificatesData = [
    {
        id: 1,
        title: 'Udemy Certificate of Completion',
        issuer: 'Udemy',
        date: '2024',
        description: 'Successfully completed the comprehensive course on Udemy, covering key concepts and practical applications.',
        image: 'https://udemy-certificate.s3.amazonaws.com/image/UC-fc5e81aa-82be-4709-8f64-ca7141c718dc.jpg',
        link: 'https://www.udemy.com/certificate/UC-fc5e81aa-82be-4709-8f64-ca7141c718dc/',
    },
    {
        id: 2,
        title: 'Doppelganger — Certificate of Participation',
        issuer: 'openpools.in',
        date: '2025',
        description: 'Participated in Doppelganger, a collaborative 30-hour build sprint hosted on OpenPools, where teams transformed their Professional DNA into real-world solutions.',
        image: doppelgangerCert,
        link: 'https://www.openpools.in',
    },
];

const Certificates = () => {
    const [selectedId, setSelectedId] = useState(null);

    return (
        <section id="certificates" className="section">
            <div className="container">
                <h2 className="section-title">Certifications</h2>

                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '30px' }}>
                    {certificatesData.map((cert, index) => (
                        <motion.div
                            layoutId={`card-container-${cert.id}`}
                            key={cert.id}
                            className="glass-card"
                            initial={{ opacity: 0, y: 20 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true }}
                            transition={{ delay: index * 0.1 }}
                            onClick={() => setSelectedId(cert.id)}
                            style={{ cursor: 'pointer', overflow: 'hidden' }}
                        >
                            <motion.div className="cert-image-container" style={{ height: '200px', overflow: 'hidden', position: 'relative' }}>
                                <motion.img
                                    src={cert.image}
                                    alt={cert.title}
                                    style={{ width: '100%', height: '100%', objectFit: 'cover', transition: 'transform 0.5s ease' }}
                                    whileHover={{ scale: 1.05 }}
                                />
                            </motion.div>
                            <div style={{ padding: '25px' }}>
                                <motion.h3 style={{ marginBottom: '10px', fontSize: '1.5rem', fontWeight: '700' }}>{cert.title}</motion.h3>
                                <motion.p style={{ color: 'var(--primary-color)', fontWeight: '600', marginBottom: '12px', fontSize: '1.2rem' }}>{cert.issuer}</motion.p>
                                <motion.p style={{ color: 'var(--text-secondary)', fontSize: '1.1rem', lineHeight: '1.7' }}>
                                    {cert.description}
                                </motion.p>
                            </div>
                        </motion.div>
                    ))}
                </div>

                <AnimatePresence>
                    {selectedId && (
                        <motion.div
                            layoutId={`card-container-${selectedId}`}
                            className="modal-overlay"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            style={{
                                position: 'fixed',
                                top: 0,
                                left: 0,
                                right: 0,
                                bottom: 0,
                                background: 'rgba(0,0,0,0.8)',
                                zIndex: 1000,
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center',
                                padding: '20px'
                            }}
                            onClick={() => setSelectedId(null)}
                        >
                            <motion.div
                                className="glass-card"
                                style={{
                                    maxWidth: '800px',
                                    width: '100%',
                                    maxHeight: '90vh',
                                    overflowY: 'auto',
                                    background: 'var(--surface-color)',
                                    padding: '0',
                                    position: 'relative'
                                }}
                                onClick={(e) => e.stopPropagation()}
                            >
                                <button
                                    onClick={() => setSelectedId(null)}
                                    style={{
                                        position: 'absolute',
                                        top: '15px',
                                        right: '15px',
                                        background: 'rgba(0,0,0,0.5)',
                                        border: 'none',
                                        color: 'white',
                                        width: '30px',
                                        height: '30px',
                                        borderRadius: '50%',
                                        cursor: 'pointer',
                                        zIndex: 10,
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'center'
                                    }}
                                >
                                    ✕
                                </button>

                                {certificatesData.filter(c => c.id === selectedId).map(cert => (
                                    <div key={cert.id}>
                                        <img
                                            src={cert.image}
                                            alt={cert.title}
                                            style={{ width: '100%', maxHeight: '500px', objectFit: 'contain', background: '#000' }}
                                        />
                                        <div style={{ padding: '40px' }}>
                                            <h2 style={{ marginBottom: '15px', color: 'var(--text-main)', fontSize: '2.5rem' }}>{cert.title}</h2>
                                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px', fontSize: '1.2rem' }}>
                                                <span style={{ color: 'var(--primary-color)', fontWeight: 'bold' }}>{cert.issuer}</span>
                                                <span style={{ color: 'var(--text-secondary)' }}>{cert.date}</span>
                                            </div>
                                            <p style={{ color: 'var(--text-secondary)', lineHeight: '1.8', marginBottom: '30px', fontSize: '1.25rem' }}>
                                                {cert.description}
                                            </p>

                                            <div style={{ display: 'flex', gap: '15px' }}>
                                                <a
                                                    href={cert.link}
                                                    target="_blank"
                                                    rel="noopener noreferrer"
                                                    className="btn btn-primary"
                                                    style={{ textDecoration: 'none', display: 'inline-block' }}
                                                >
                                                    Verify Credential
                                                </a>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </motion.div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </section>
    );
};

export default Certificates;

import React, { useReducer, useState } from 'react';
import { motion } from 'framer-motion';
import { FaGithub, FaLinkedin, FaPhone, FaMapMarkerAlt, FaPaperPlane } from 'react-icons/fa';
import { MdEmail } from 'react-icons/md';
import { SiLeetcode } from 'react-icons/si';
import emailjs from '@emailjs/browser';

// useReducer: Managing complex form state
const initialState = {
    name: '',
    email: '',
    message: '',
    status: 'idle', // idle, submitting, success, error
    errors: {}
};

const formReducer = (state, action) => {
    switch (action.type) {
        case 'SET_FIELD':
            return {
                ...state,
                [action.field]: action.value,
                errors: { ...state.errors, [action.field]: '' }
            };
        case 'SUBMIT_START':
            return { ...state, status: 'submitting' };
        case 'SUBMIT_SUCCESS':
            return { ...initialState, status: 'success' };
        case 'SUBMIT_ERROR':
            return { ...state, status: 'error', errors: action.errors };
        case 'RESET_STATUS':
            return { ...state, status: 'idle' };
        default:
            return state;
    }
};

// --- Sub-components moved outside Contact to fix focus loss (typing bug) ---

const LoadingSpinner = () => (
    <svg className="w-5 h-5" style={{ animation: 'spin 1s linear infinite' }} viewBox="0 0 24 24" fill="none">
        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" />
        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
    </svg>
);

const InputField = ({ label, name, type = "text", value, error, isTextArea = false, onChange, onFocus, onBlur, focusedField }) => {
    const isFocused = focusedField === name;
    const hasValue = value.length > 0;
    const isActive = isFocused || hasValue;

    const baseInputClasses = `w-full px-4 py-3 rounded-xl text-[var(--text-main)] text-base outline-none transition-all duration-300 
        bg-white/[0.05] border ${error ? 'border-red-500' : isFocused ? 'border-[#A855F7]' : 'border-white/10'}`;

    const focusGlowStyle = isFocused ? {
        boxShadow: '0 0 15px rgba(168, 85, 247, 0.3), 0 0 30px rgba(168, 85, 247, 0.1)',
        animation: 'focus-glow-pulse 2s ease-in-out infinite'
    } : {};

    return (
        <div className="relative mb-6">
            <label
                className={`absolute left-4 transition-all duration-300 pointer-events-none ${isActive
                    ? 'top-[-10px] text-xs px-2 bg-[#161d2f] rounded'
                    : 'top-3 text-sm'
                    }`}
                style={{ color: isFocused ? '#A855F7' : 'var(--text-secondary)' }}
            >
                {label}
            </label>
            {isTextArea ? (
                <textarea
                    name={name}
                    value={value}
                    onChange={onChange}
                    onFocus={() => onFocus(name)}
                    onBlur={() => onBlur(null)}
                    rows="4"
                    className={baseInputClasses + ' resize-none'}
                    style={focusGlowStyle}
                />
            ) : (
                <input
                    type={type}
                    name={name}
                    value={value}
                    onChange={onChange}
                    onFocus={() => onFocus(name)}
                    onBlur={() => onBlur(null)}
                    className={baseInputClasses}
                    style={focusGlowStyle}
                />
            )}
            {error && (
                <span className="absolute bottom-[-20px] left-0 text-red-400 text-xs">
                    {error}
                </span>
            )}
        </div>
    );
};

// --- Main Contact Component ---

const Contact = () => {
    const [state, dispatch] = useReducer(formReducer, initialState);
    const [focusedField, setFocusedField] = useState(null);

    const validate = () => {
        const errors = {};
        if (!state.name.trim()) errors.name = 'Name is required';
        if (!state.email.includes('@')) errors.email = 'Valid email is required';
        if (state.message.length < 10) errors.message = 'Message must be at least 10 characters';
        return errors;
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        const errors = validate();
        if (Object.keys(errors).length > 0) {
            dispatch({ type: 'SUBMIT_ERROR', errors });
            return;
        }
        try {
            dispatch({ type: 'SUBMIT_START' });

            // Using Vite environment variables (configurable in .env)
            const serviceId = import.meta.env.VITE_EMAILJS_SERVICE_ID;
            const templateId = import.meta.env.VITE_EMAILJS_TEMPLATE_ID;
            const publicKey = import.meta.env.VITE_EMAILJS_PUBLIC_KEY;

            // Extra check for leftover placeholders in .env
            const isPlaceholder = (val) => !val || val.includes('your_') || val.length < 5;

            if (isPlaceholder(serviceId) || isPlaceholder(templateId) || isPlaceholder(publicKey)) {
                console.error("DEBUG: One or more EmailJS keys are still placeholders or missing in .env.");
                throw new Error("EmailJS is not fully configured. Please check your .env file and ensure values like 'your_service_id' are replaced with real keys.");
            }

            // Enhanced Template Parameters (Ensure these match your EmailJS Dashboard)
            const templateParams = {
                from_name: state.name,
                from_email: state.email,
                to_name: 'Aman', // Your name (recipient)
                message: state.message,
                reply_to: state.email, // This allows you to reply directly to the sender
            };

            const response = await emailjs.send(
                serviceId,
                templateId,
                templateParams,
                publicKey
            );
            console.log('SUCCESS!', response.status, response.text);
            dispatch({ type: 'SUBMIT_SUCCESS' });
            setTimeout(() => dispatch({ type: 'RESET_STATUS' }), 4000);
        } catch (err) {
            console.log('FAILED...', err);
            dispatch({
                type: 'SUBMIT_ERROR',
                errors: { submit: err.message || 'Failed to send message. Please try again later.' }
            });
        }
    };

    const handleChange = (e) => {
        dispatch({ type: 'SET_FIELD', field: e.target.name, value: e.target.value });
    };

    const socialLinks = [
        { icon: <FaLinkedin size={20} />, href: 'https://www.linkedin.com/in/aman-kumar-067825379/', label: 'LinkedIn', color: '#0077b5' },
        { icon: <FaGithub size={20} />, href: 'https://github.com/amankumarb778-crypto', label: 'GitHub', color: '#fff' },
        { icon: <SiLeetcode size={20} />, href: 'https://leetcode.com/u/OVzm6rcAP2/', label: 'LeetCode', color: '#f89f1b' },
    ];

    const contactDetails = [
        { icon: <MdEmail />, text: 'aman.kr.cg@gmail.com', href: 'mailto:aman.kr.cg@gmail.com' },
        { icon: <FaPhone />, text: '+91 92798 11913', href: 'tel:+919279811913' },
        { icon: <FaMapMarkerAlt />, text: 'India', href: null },
    ];

    return (
        <section id="contact" className="section relative overflow-hidden">
            {/* Background Glow Blobs */}
            <div
                className="absolute top-1/2 left-[20%] w-[600px] h-[600px] pointer-events-none"
                style={{
                    background: 'radial-gradient(circle, rgba(168, 85, 247, 0.12) 0%, transparent 70%)',
                    transform: 'translate(-50%, -50%)',
                }}
            />
            <div
                className="absolute bottom-0 right-[10%] w-[400px] h-[400px] pointer-events-none"
                style={{
                    background: 'radial-gradient(circle, rgba(217, 70, 239, 0.08) 0%, transparent 70%)',
                }}
            />

            <div className="container">
                {/* Section Title */}
                <motion.h2
                    className="section-title text-center mb-16"
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.6 }}
                    viewport={{ once: true }}
                    style={{ fontFamily: 'var(--font-heading)' }}
                >
                    Get In <span style={{ color: 'var(--primary-color)' }}>Touch</span>
                </motion.h2>

                <motion.div
                    initial={{ opacity: 0, y: 50 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.8 }}
                    viewport={{ once: true }}
                    className="max-w-[1000px] mx-auto rounded-2xl overflow-hidden border border-white/10"
                    style={{
                        background: 'rgba(255, 255, 255, 0.05)',
                        backdropFilter: 'blur(20px)',
                        WebkitBackdropFilter: 'blur(20px)',
                        boxShadow: '0 8px 32px rgba(0, 0, 0, 0.4), inset 0 1px 0 rgba(255,255,255,0.05)',
                    }}
                >
                    <div className="grid grid-cols-1 md:grid-cols-2">
                        {/* Left Side: Contact Info */}
                        <div
                            className="p-10 md:p-14 flex flex-col justify-between relative overflow-hidden"
                            style={{
                                background: 'linear-gradient(135deg, rgba(168, 85, 247, 0.9), rgba(217, 70, 239, 0.85))',
                            }}
                        >
                            <div className="absolute -top-20 -right-20 w-60 h-60 rounded-full bg-white/10 pointer-events-none" />
                            <div className="absolute -bottom-10 -left-10 w-40 h-40 rounded-full bg-white/5 pointer-events-none" />

                            <div className="relative z-10">
                                <h2
                                    className="text-3xl md:text-4xl font-bold mb-4 text-white"
                                    style={{ fontFamily: 'var(--font-heading)' }}
                                >
                                    Let's Work Together
                                </h2>
                                <p className="text-white/85 leading-relaxed mb-10 text-lg">
                                    I'm always open to discussing new projects, creative ideas, or opportunities to be part of your vision.
                                </p>

                                <div className="flex flex-col gap-5">
                                    {contactDetails.map((detail, idx) => {
                                        const Content = (
                                            <>
                                                <span className="bg-white/20 p-2.5 rounded-full flex items-center justify-center">
                                                    {detail.icon}
                                                </span>
                                                {detail.text}
                                            </>
                                        );

                                        return detail.href ? (
                                            <motion.a
                                                key={idx}
                                                href={detail.href}
                                                className="flex items-center gap-4 text-white no-underline text-base"
                                                whileHover={{ x: 5 }}
                                                transition={{ duration: 0.2 }}
                                            >
                                                {Content}
                                            </motion.a>
                                        ) : (
                                            <div
                                                key={idx}
                                                className="flex items-center gap-4 text-white/85 text-base"
                                            >
                                                {Content}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>

                            <div className="flex gap-4 mt-10 relative z-10">
                                {socialLinks.map((social, index) => (
                                    <motion.a
                                        key={index}
                                        href={social.href}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        whileHover={{
                                            scale: 1.15,
