const SectionHeader = ({ icon, label }) => (
    <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 4 }}>
        {icon}
        <Typography variant="h5" fontWeight={800} sx={{ color: '#fff', whiteSpace: 'nowrap' }}>
            {label}
        </Typography>
        <Box sx={{ flexGrow: 1, height: '1px', background: 'linear-gradient(90deg, rgba(255,255,255,0.12), transparent)' }} />
    </Box>
);

const Projects = () => {
    const [tab, setTab] = useState(0);

    const filtered = () => {
        const t = TABS[tab];
        if (t === 'All') return projectsData;
        if (t === 'Featured') return projectsData.filter(p => !p.isHackathon);
        if (t === 'Hackathon') return projectsData.filter(p => p.isHackathon);
        return projectsData.filter(p => p.category === t);
    };

    const showSections = tab === 0;
    const featuredProjects = projectsData.filter(p => !p.isHackathon);
    const hackathonProjects = projectsData.filter(p => p.isHackathon);

    return (
        <Box
            component="section"
            id="projects"
            sx={{ py: { xs: 8, md: 12 }, background: 'var(--bg-color)', px: { xs: 2, sm: 4, md: 6 } }}
        >
            {/* Header */}
            <Box sx={{ textAlign: 'center', mb: 7 }}>
                <motion.div initial={{ opacity: 0, y: -20 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true }} transition={{ duration: 0.5 }}>
                    <Typography
                        variant="h3"
                        fontWeight={900}
                        sx={{ color: '#fff', fontSize: { xs: '2rem', md: '2.8rem' }, mb: 1.5 }}
                    >
                        Project Portfolio
                    </Typography>
                    <Typography
                        variant="body1"
                        sx={{ color: 'rgba(255,255,255,0.5)', maxWidth: 560, mx: 'auto', mb: 4, lineHeight: 1.7 }}
                    >
                        A curated selection of my best work — from AI-powered tools to high-performance web apps.
                    </Typography>
                </motion.div>

                {/* Tabs */}
                <Tabs
                    value={tab}
                    onChange={(_, v) => setTab(v)}
                    centered
                    scrollButtons="auto"
                    variant="scrollable"
                    sx={{
                        '& .MuiTabs-indicator': { background: 'var(--primary-color)', height: 3, borderRadius: 2 },
                        '& .MuiTab-root': {
                            color: 'rgba(255,255,255,0.45)',
                            fontWeight: 700,
                            textTransform: 'none',
                            fontSize: '0.95rem',
                            minWidth: 80,
                        },
                        '& .Mui-selected': { color: '#fff !important' },
                    }}
                >
                    {TABS.map(t => <Tab key={t} label={t} />)}
                </Tabs>
            </Box>

            {/* Cards */}
            <AnimatePresence mode="wait">
                {showSections ? (
                    <motion.div key="sections" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
                        {/* Featured */}
                        {featuredProjects.length > 0 && (
                            <Box sx={{ mb: 8 }}>
                                <SectionHeader
                                    icon={<WorkspacePremiumIcon sx={{ color: 'var(--primary-color)', fontSize: '1.8rem' }} />}
                                    label="Featured Work"
                                />
                                <Grid container spacing={3}>
                                    {featuredProjects.map((p, i) => (
                                        <Grid item xs={12} sm={6} lg={4} key={p.id}>
                                            <ProjectCard project={p} index={i} />
                                        </Grid>
                                    ))}
                                </Grid>
                            </Box>
                        )}
                        {/* Hackathon */}
                        {hackathonProjects.length > 0 && (
                            <Box>
                                <SectionHeader
                                    icon={<EmojiEventsIcon sx={{ color: '#FFD700', fontSize: '1.8rem' }} />}
                                    label="Hackathon Entries"
                                />
                                <Grid container spacing={3}>
                                    {hackathonProjects.map((p, i) => (
                                        <Grid item xs={12} sm={6} lg={4} key={p.id}>
                                            <ProjectCard project={p} index={i} />
                                        </Grid>
                                    ))}
                                </Grid>
                            </Box>
                        )}
                    </motion.div>
                ) : (
                    <motion.div key={tab} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }} transition={{ duration: 0.3 }}>
                        <Grid container spacing={3}>
                            {filtered().map((p, i) => (
                                <Grid item xs={12} sm={6} lg={4} key={p.id}>
                                    <ProjectCard project={p} index={i} />
                                </Grid>
                            ))}
                        </Grid>
                    </motion.div>
                )}
            </AnimatePresence>
        </Box>
    );
};

export default Projects;

import React, { useMemo, useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { FaReact, FaJs, FaHtml5, FaCss3Alt, FaNode, FaGitAlt, FaFigma } from 'react-icons/fa';
import { SiMongodb, SiLeetcode } from 'react-icons/si';

const Skills = () => {
    const rawSkills = [
        { name: 'React', category: 'Frontend', level: 90, icon: <FaReact /> },
        { name: 'JavaScript', category: 'Frontend', level: 85, icon: <FaJs /> },
        { name: 'HTML5', category: 'Frontend', level: 95, icon: <FaHtml5 /> },
        { name: 'CSS3', category: 'Frontend', level: 90, icon: <FaCss3Alt /> },
        { name: 'Node.js', category: 'Backend', level: 75, icon: <FaNode /> },
        { name: 'MongoDB', category: 'Backend', level: 70, icon: <SiMongodb /> },
        { name: 'Figma', category: 'Design', level: 80, icon: <FaFigma /> },
        { name: 'Git', category: 'Tools', level: 85, icon: <FaGitAlt /> }
    ];

    // useMemo: Optimizing performance by caching sorted/filtered results
    // In a real app with large datasets or complex sorting, this prevents recalculation on every render
    const sortedSkills = useMemo(() => {
        return rawSkills.sort((a, b) => b.level - a.level);
    }, []);

    const [leetcodeStats, setLeetcodeStats] = useState(null);

    useEffect(() => {
        const fetchLeetCodeStats = async () => {
            try {
                const response = await fetch('https://leetcode-stats-api.herokuapp.com/OVzm6rcAP2');
                const data = await response.json();
                if (data.status === 'success') {
                    setLeetcodeStats(data);
                }
            } catch (error) {
                console.error("Failed to fetch LeetCode stats:", error);
            }
        };
        fetchLeetCodeStats();
    }, []);

    return (
        <section id="skills" className="section">
            <div className="container">
                <h2 className="section-title">Technical Skills</h2>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '30px', marginBottom: '60px' }}>
                    {sortedSkills.map((skill, index) => (
                        <motion.div
                            key={skill.name}
                            className="glass-card"
                            initial={{ opacity: 0, y: 30 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true }}
                            transition={{ delay: index * 0.1 }}
                            whileHover={{ y: -10, boxShadow: '0 10px 30px rgba(0,0,0,0.2)' }}
                            style={{ padding: '30px', textAlign: 'center', cursor: 'pointer' }}
                        >
                            <div style={{ fontSize: '3rem', color: 'var(--primary-color)', marginBottom: '15px' }}>
                                {skill.icon}
                            </div>
                            <h3 style={{ marginBottom: '10px' }}>{skill.name}</h3>
                            <div style={{ width: '100%', height: '6px', background: 'rgba(255,255,255,0.1)', borderRadius: '3px', overflow: 'hidden' }}>
                                <motion.div
                                    initial={{ width: 0 }}
                                    whileInView={{ width: `${skill.level}%` }}
                                    transition={{ duration: 1, delay: 0.5 }}
                                    style={{ height: '100%', background: 'var(--secondary-color)' }}
                                />
                            </div>
                        </motion.div>
                    ))}
                </div>

                {/* LeetCode Stats Section */}
                {leetcodeStats && (
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.6 }}
                        className="glass-card"
                        style={{
                            padding: '40px',
                            maxWidth: '900px',
                            margin: '0 auto',
                            background: 'linear-gradient(145deg, rgba(23, 25, 35, 0.95), rgba(17, 24, 39, 0.9))',
                            border: '1px solid rgba(248, 159, 27, 0.15)',
                            position: 'relative',
                            overflow: 'hidden'
                        }}
                    >
                        {/* Background decoration */}
                        <div style={{
                            position: 'absolute',
                            top: '-50%',
                            right: '-20%',
                            width: '400px',
                            height: '400px',
                            background: 'radial-gradient(circle, rgba(248, 159, 27, 0.05) 0%, transparent 70%)',
                            pointerEvents: 'none'
                        }} />

                        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: '40px' }}>
                            <div style={{
                                display: 'flex',
                                alignItems: 'center',
                                gap: '15px',
                                background: 'rgba(255,255,255,0.03)',
                                padding: '10px 25px',
                                borderRadius: '50px',
                                border: '1px solid rgba(255,255,255,0.05)'
                            }}>
                                <SiLeetcode size={28} color="#f89f1b" />
                                <h3 style={{ fontSize: '1.8rem', margin: 0, fontWeight: '700' }}>LeetCode Profile</h3>
                            </div>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '30px' }}>

                            {/* Main Stats Circle */}
                            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
                                <div style={{
                                    width: '140px',
                                    height: '140px',
                                    borderRadius: '50%',
                                    border: '4px solid rgba(255,255,255,0.1)',
                                    display: 'flex',
                                    flexDirection: 'column',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    position: 'relative',
                                    boxShadow: '0 0 30px rgba(0,0,0,0.3)'
                                }}>
                                    <div style={{ fontSize: '3rem', fontWeight: '800', color: 'white' }}>
                                        {leetcodeStats.totalSolved}
                                    </div>
                                    <div style={{ fontSize: '1rem', color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '1px' }}>Solved</div>

                                    {/* Decorative ring */}
                                    <div style={{
                                        position: 'absolute',
                                        top: '-4px',
                                        left: '-4px',
                                        right: '-4px',
                                        bottom: '-4px',
                                        borderRadius: '50%',
                                        border: '4px solid transparent',
                                        borderTopColor: '#f89f1b',
                                        transform: 'rotate(-45deg)'
                                    }} />
                                </div>
                                <div style={{ marginTop: '20px', textAlign: 'center' }}>
                                    <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Global Ranking</div>
                                    <div style={{ fontSize: '1.2rem', fontWeight: 'bold', color: 'white' }}>#{leetcodeStats.ranking.toLocaleString()}</div>
                                </div>
                            </div>

                            {/* Difficulty Breakdown */}
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px', justifyContent: 'center' }}>
                                {[
                                    { label: 'Easy', count: leetcodeStats.easySolved, total: leetcodeStats.totalEasy, color: '#22c55e', bg: 'rgba(34, 197, 94, 0.1)' },
                                    { label: 'Medium', count: leetcodeStats.mediumSolved, total: leetcodeStats.totalMedium, color: '#eab308', bg: 'rgba(234, 179, 8, 0.1)' },
                                    { label: 'Hard', count: leetcodeStats.hardSolved, total: leetcodeStats.totalHard, color: '#ef4444', bg: 'rgba(239, 68, 68, 0.1)' }
                                ].map((item) => (
                                    <div key={item.label} style={{
                                        padding: '15px 20px',
                                        background: 'rgba(255,255,255,0.03)',
                                        borderRadius: '12px',
                                        display: 'flex',
                                        alignItems: 'center',
                                        justifyContent: 'space-between',
                                        transition: 'transform 0.2s',
                                        hover: { transform: 'translateX(5px)' }
                                    }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                            <span style={{
                                                width: '8px',
                                                height: '8px',
                                                borderRadius: '50%',
                                                background: item.color,
                                                boxShadow: `0 0 10px ${item.color}`
                                            }} />
                                            <span style={{ color: 'var(--text-secondary)', fontSize: '0.95rem' }}>{item.label}</span>
                                        </div>
                                        <div style={{ display: 'flex', alignItems: 'baseline', gap: '5px' }}>
                                            <span style={{ fontSize: '1.2rem', fontWeight: 'bold', color: 'white' }}>{item.count}</span>
                                            <span style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.3)' }}>/ {item.total}</span>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        <div style={{
                            marginTop: '40px',
                            paddingTop: '20px',
                            borderTop: '1px solid rgba(255,255,255,0.05)',
                            display: 'flex',
                            justifyContent: 'space-between',
                            alignItems: 'center',
                            flexWrap: 'wrap',
                            gap: '20px'
                        }}>
                            <div style={{ display: 'flex', gap: '20px' }}>
                                <div>
                                    <span style={{ display: 'block', fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Acceptance Rate</span>
                                    <span style={{ fontSize: '1.1rem', fontWeight: '600', color: 'white' }}>{leetcodeStats.acceptanceRate}%</span>
                                </div>
                                <div>
                                    <span style={{ display: 'block', fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Contributions</span>
                                    <span style={{ fontSize: '1.1rem', fontWeight: '600', color: 'white' }}>{leetcodeStats.contributionPoints}</span>
                                </div>
                            </div>

                            <motion.a
                                href="https://leetcode.com/u/OVzm6rcAP2/"
                                target="_blank"
                                rel="noopener noreferrer"
                                whileHover={{ x: 5 }}
                                style={{
                                    color: '#f89f1b',
                                    textDecoration: 'none',
                                    fontWeight: '500',
                                    display: 'flex',
                                    alignItems: 'center',
                                    gap: '8px'
                                }}
                            >
                                View full profile <span>→</span>
                            </motion.a>
                        </div>
                    </motion.div>
                )}
            </div>
        </section>
    );
};

export default Skills;

import React, { createContext, useState, useEffect, useContext } from 'react';

const ThemeContext = createContext();

export const useTheme = () => useContext(ThemeContext);

export const ThemeProvider = ({ children }) => {
    // Initialize state from local storage or default to 'dark'
    const [theme, setTheme] = useState(() => {
        return localStorage.getItem('portfolio-theme') || 'dark';
    });

    // useEffect to apply theme class to body and save to local storage
    // REASON: Synchronizing React state (theme) with external side effects (DOM class, LocalStorage).
    useEffect(() => {
        document.documentElement.setAttribute('data-theme', theme);
        localStorage.setItem('portfolio-theme', theme);
    }, [theme]);

    const toggleTheme = () => {
        setTheme((prev) => (prev === 'dark' ? 'light' : 'dark'));
    };

    return (
        <ThemeContext.Provider value={{ theme, toggleTheme }}>
            {children}
        </ThemeContext.Provider>
    );
};
